# Generated by google (gemini-2.5-flash)
# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import argparse
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import NoBrokersAvailable

def create_topic(admin_client, topic_name, num_partitions, replication_factor, config_settings):
    try:
        new_topic = NewTopic(
            name=topic_name,
            num_partitions=num_partitions,
            replication_factor=replication_factor,
            topic_configs=config_settings
        )
        admin_client.create_topics([new_topic], validate_only=False)
        print(f"Topic '{topic_name}' created successfully with {num_partitions} partitions and replication factor {replication_factor}.")
        if config_settings:
            print(f"Applied configurations: {config_settings}")
    except Exception as e:
        print(f"Error creating topic '{topic_name}': {e}")

def describe_topics(admin_client, topic_names):
    try:
        if not topic_names:
            topic_names = list(admin_client.list_topics())
            print("Listing all topics:")
        else:
            print(f"Describing topics: {', '.join(topic_names)}")

        topic_metadata = admin_client.describe_topics(topic_names)
        for metadata in topic_metadata:
            print(f"\nTopic: {metadata['topic']}")
            print(f"  Partitions: {len(metadata['partitions'])}")
            print(f"  Replication Factor: {len(metadata['partitions'][0]['replicas']) if metadata['partitions'] else 'N/A'}")
            print("  Partition Details:")
            for p in metadata['partitions']:
                print(f"    Partition {p['partition']}: Leader {p['leader']}, Replicas {p['replicas']}, ISR {p['isr']}")
    except Exception as e:
        print(f"Error describing topics: {e}")

def describe_topic_configs(admin_client, topic_name):
    try:
        config_resource = ConfigResource(ConfigResourceType.TOPIC, topic_name)
        configs = admin_client.describe_configs([config_resource])
        print(f"\nConfiguration for topic '{topic_name}':")
        for config_entry in configs:
            if config_entry.resource_name == topic_name and config_entry.resource_type == ConfigResourceType.TOPIC:
                for key, value in config_entry.configs.items():
                    print(f"  {key}: {value.value} (Read-only: {value.read_only}, Default: {value.is_default}, Sensitive: {value.is_sensitive})")
                return
        print(f"No configuration found for topic '{topic_name}'.")
    except Exception as e:
        print(f"Error describing topic configuration for '{topic_name}': {e}")

def alter_topic_configs(admin_client, topic_name, config_settings):
    try:
        if not config_settings:
            print("No configuration settings provided for alteration.")
            return

        config_resource = ConfigResource(ConfigResourceType.TOPIC, topic_name, configs=config_settings)
        admin_client.alter_configs([config_resource])
        print(f"Topic '{topic_name}' configurations altered successfully.")
        print(f"Applied configurations: {config_settings}")
    except Exception as e:
        print(f"Error altering topic '{topic_name}' configurations: {e}")

def delete_topics(admin_client, topic_names):
    try:
        if not topic_names:
            print("No topic names provided for deletion.")
            return

        admin_client.delete_topics(topic_names)
        print(f"Topics '{', '.join(topic_names)}' deletion initiated.")
        print("Note: Topic deletion might take some time to propagate across the cluster.")
    except Exception as e:
        print(f"Error deleting topics '{', '.join(topic_names)}': {e}")

def create_partitions(admin_client, topic_name, new_total_partitions):
    try:
        # Get current topic info to determine current partition count
        topic_metadata = admin_client.describe_topics([topic_name])
        if not topic_metadata:
            print(f"Topic '{topic_name}' not found.")
            return

        current_partitions = len(topic_metadata[0]['partitions'])
        if new_total_partitions <= current_partitions:
            print(f"New partition count ({new_total_partitions}) must be greater than current count ({current_partitions}). No action taken.")
            return

        admin_client.create_partitions({topic_name: new_total_partitions})
        print(f"Successfully increased partitions for topic '{topic_name}' to {new_total_partitions}.")
    except Exception as e:
        print(f"Error creating partitions for topic '{topic_name}': {e}")


def main():
    parser = argparse.ArgumentParser(
        description="Kafka Topic Administration Script using kafka-python AdminClient.",
        formatter_class=argparse.RawTextHelpFormatter
    )
    parser.add_argument('--bootstrap-servers', default='localhost:9092',
                        help='Comma-separated list of Kafka bootstrap servers (default: localhost:9092)')

    subparsers = parser.add_subparsers(dest='command', required=True, help='Available commands')

    # Create Topic
    create_parser = subparsers.add_parser('create', help='Create a new Kafka topic.')
    create_parser.add_argument('--topic', required=True, help='Name of the topic to create.')
    create_parser.add_argument('--partitions', type=int, default=1,
                               help='Number of partitions for the topic (default: 1).')
    create_parser.add_argument('--replication-factor', type=int, default=1,
                               help='Replication factor for the topic (default: 1).')
    create_parser.add_argument('--config', nargs='*', default=[],
                               help='Topic configuration settings in key=value format (e.g., --config "retention.ms=604800000" "cleanup.policy=delete").')

    # Describe Topics
    describe_parser = subparsers.add_parser('describe', help='Describe one or more Kafka topics.')
    describe_parser.add_argument('--topic', nargs='*', default=[],
                                 help='Name(s) of the topic(s) to describe. If omitted, all topics will be listed.')

    # Describe Topic Configs
    describe_config_parser = subparsers.add_parser('describe-config', help='Describe configuration for a specific Kafka topic.')
    describe_config_parser.add_argument('--topic', required=True, help='Name of the topic to describe configurations for.')

    # Alter Topic Configs
    alter_config_parser = subparsers.add_parser('alter-config', help='Alter configuration settings for an existing Kafka topic.')
    alter_config_parser.add_argument('--topic', required=True, help='Name of the topic to alter configurations for.')
    alter_config_parser.add_argument('--config', nargs='*', default=[],
                                     help='Topic configuration settings to alter in key=value format (e.g., --config "retention.ms=604800000").')

    # Delete Topics
    delete_parser = subparsers.add_parser('delete', help='Delete one or more Kafka topics.')
    delete_parser.add_argument('--topic', nargs='+', required=True,
                               help='Name(s) of the topic(s) to delete.')

    # Create Partitions (Increase)
    add_partitions_parser = subparsers.add_parser('add-partitions', help='Increase the number of partitions for an existing topic.')
    add_partitions_parser.add_argument('--topic', required=True, help='Name of the topic to add partitions to.')
    add_partitions_parser.add_argument('--new-total-partitions', type=int, required=True,
                                       help='The new total number of partitions for the topic. Must be greater than current count.')


    args = parser.parse_args()

    try:
        admin_client = KafkaAdminClient(
            bootstrap_servers=args.bootstrap_servers,
            client_id='kafka-admin-script'
        )
    except NoBrokersAvailable:
        print(f"Error: Could not connect to Kafka bootstrap servers at {args.bootstrap_servers}.")
        print("Please ensure Kafka brokers are running and accessible.")
        return
    except Exception as e:
        print(f"An unexpected error occurred during AdminClient initialization: {e}")
        return

    config_dict = {}
    if hasattr(args, 'config') and args.config:
        for item in args.config:
            if '=' in item:
                key, value = item.split('=', 1)
                config_dict[key.strip()] = value.strip()
            else:
                print(f"Warning: Invalid config format '{item}'. Expected key=value.")

    try:
        if args.command == 'create':
            create_topic(admin_client, args.topic, args.partitions, args.replication_factor, config_dict)
        elif args.command == 'describe':
            describe_topics(admin_client, args.topic)
        elif args.command == 'describe-config':
            describe_topic_configs(admin_client, args.topic)
        elif args.command == 'alter-config':
            alter_topic_configs(admin_client, args.topic, config_dict)
        elif args.command == 'delete':
            delete_topics(admin_client, args.topic)
        elif args.command == 'add-partitions':
            create_partitions(admin_client, args.topic, args.new_total_partitions)
    finally:
        admin_client.close()

if __name__ == '__main__':
    main()